1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	};
7	
8	export type QuoteStep = { kind: "quote"; items: Item[] };
9	
10	export type Damage = { itemType: string; amount: number };
11	
12	export type ClaimStep = {
13	  kind: "claim";
14	  policy: number;
15	  incident: { cause?: string; damages: Damage[] };
16	};
17	
18	export type Step = QuoteStep | ClaimStep;
19	
20	export type Customer = { yearsWithMHPCO: number };
21	
22	export type Scenario = {
23	  customer: Customer;
24	  steps: Step[];
25	};
26	
27	export type ScenarioResult = {
28	  results: unknown[];
29	};
30	
31	const COMPONENT_BASE_PREMIUM = 25;
32	
33	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: COMPONENT_BASE_PREMIUM,
39	  moonstone: COMPONENT_BASE_PREMIUM,
40	};
41	
42	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
43	const PER_CONTRACT_DISCOUNT_RATE = 0.15;
44	const LOYALTY_DISCOUNT_RATE = 0.2;
45	const LOYALTY_THRESHOLD_YEARS = 2;
46	const PROCESSING_FEE = 5;
47	
48	const CURSED_SURCHARGE_RATE = 0.5;
49	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const HIGH_ENCHANTMENT_THRESHOLD = 5;
51	
52	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
53	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
54	const DRAGON_MATERIAL = "dragon";
55	const DRAGON_MATERIAL_REIMBURSEMENT_RATE = 1.0;
56	const DEDUCTIBLE = 100;
57	
58	function isCursed(item: Item): boolean {
59	  return item.cursed === true;
60	}
61	
62	function enchantmentLevel(item: Item): number {
63	  return item.enchantment ?? 0;
64	}
65	
66	function isHighlyEnchanted(item: Item): boolean {
67	  return enchantmentLevel(item) >= HIGH_ENCHANTMENT_THRESHOLD;
68	}
69	
70	function qualifiesForHighEnchantmentReimbursement(item: Item): boolean {
71	  return enchantmentLevel(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
72	}
73	
74	function riskMultiplierForItem(item: Item): number {
75	  return (
76	    1 +
77	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
78	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
79	  );
80	}
81	
82	function basePremiumForItem(item: Item): number {
83	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
84	}
85	
86	type QuoteResult = { kind: "quote"; premium: number };
87	type ClaimResult = { kind: "claim"; payout: number };
88	type StepResult = QuoteResult | ClaimResult;
89	
90	function reimbursementRateForItem(item: Item): number {
91	  if (item.material === DRAGON_MATERIAL) return DRAGON_MATERIAL_REIMBURSEMENT_RATE;
92	  if (qualifiesForHighEnchantmentReimbursement(item)) return HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
93	  return 0;
94	}
95	
96	function reimbursementForDamage(damage: Damage, policy: QuoteStep): number {
97	  const item = policy.items.find((i) => i.kind === damage.itemType);
98	  if (item === undefined) return 0;
99	  return damage.amount * reimbursementRateForItem(item);
100	}
101	
102	function claimStep(step: ClaimStep, policy: QuoteStep): ClaimResult {
103	  const reimbursable = step.incident.damages.reduce(
104	    (sum, damage) => sum + reimbursementForDamage(damage, policy),
105	    0,
106	  );
107	  const payout = Math.max(0, reimbursable - DEDUCTIBLE);
108	  return { kind: "claim", payout };
109	}
110	
111	const BUILDING_BLOCK_BASE_PREMIUM = 60;
112	const BUILDING_BLOCK_SIZE = 3;
113	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
114	
115	type ItemGroup = { kind: Item["kind"]; items: Item[] };
116	
117	function groupByKind(items: Item[]): ItemGroup[] {
118	  const groups = new Map<Item["kind"], Item[]>();
119	  for (const item of items) {
120	    const group = groups.get(item.kind) ?? [];
121	    group.push(item);
122	    groups.set(item.kind, group);
123	  }
124	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
125	}
126	
127	function isComponentKind(kind: Item["kind"]): boolean {
128	  return COMPONENT_KINDS.includes(kind);
129	}
130	
131	function isBuildingBlock(group: ItemGroup): boolean {
132	  return group.items.length === BUILDING_BLOCK_SIZE && isComponentKind(group.kind);
133	}
134	
135	function basePremiumForGroup(group: ItemGroup): number {
136	  if (isBuildingBlock(group)) {
137	    return BUILDING_BLOCK_BASE_PREMIUM;
138	  }
139	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
140	}
141	
142	function basePremiumForItems(items: Item[]): number {
143	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
144	}
145	
146	function contractSequenceRate(contractIndex: number): number {
147	  return contractIndex === 0 ? FIRST_INSURANCE_SURCHARGE_RATE : -PER_CONTRACT_DISCOUNT_RATE;
148	}
149	
150	function loyaltyRate(customer: Customer): number {
151	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? -LOYALTY_DISCOUNT_RATE : 0;
152	}
153	
154	function customerRateForContract(
155	  contractIndex: number,
156	  customer: Customer,
157	): number {
158	  return contractSequenceRate(contractIndex) + loyaltyRate(customer);
159	}
160	
161	function quoteStep(
162	  step: QuoteStep,
163	  contractIndex: number,
164	  customer: Customer,
165	): QuoteResult {
166	  const basePremium = basePremiumForItems(step.items);
167	  const customerAdjustment = basePremium * customerRateForContract(contractIndex, customer);
168	  const premium = Math.ceil(basePremium + customerAdjustment + PROCESSING_FEE);
169	  return { kind: "quote", premium };
170	}
171	
172	function processStep(
173	  step: Step,
174	  contractIndex: number,
175	  customer: Customer,
176	  steps: Step[],
177	): StepResult {
178	  if (step.kind === "quote") {
179	    return quoteStep(step, contractIndex, customer);
180	  }
181	  return claimStep(step, steps[step.policy] as QuoteStep);
182	}
183	
184	function countQuotesBefore(steps: Step[], index: number): number {
185	  return steps.slice(0, index).filter((step) => step.kind === "quote").length;
186	}
187	
188	export function processScenario(scenario: Scenario): ScenarioResult {
189	  const results = scenario.steps.map((step, index) =>
190	    processStep(step, countQuotesBefore(scenario.steps, index), scenario.customer, scenario.steps),
191	  );
192	  return { results };
193	}
